export type UserRole = 'student' | 'employer';

export enum WorkType {
  Physical = 'Fysiskt',
  Online = 'Online',
  Hybrid = 'Båda'
}

export enum ShiftType {
  Morning = 'Morgon',
  Day = 'Dag',
  Evening = 'Kväll',
  Weekend = 'Helg'
}

export interface StudentProfile {
  id: string;
  name: string;
  age: number;
  city: string;
  education: string;
  availability: ShiftType[];
  experienceTags: string[];
  workPreference: WorkType;
  verified: boolean;
  rating: number;
  jobsCompleted: number;
  responseTime: string;
}

export interface Job {
  id: string;
  title: string;
  company: string;
  employerId: string;
  city: string;
  hourlyRate: number;
  startTime: string; // e.g., "Inom 2h", "Imorgon"
  duration: string; // e.g., "4 timmar"
  workType: WorkType;
  shiftType: ShiftType;
  requirements: string[];
  description: string;
  isQuickShift: boolean; // 3-6 hours, same-day booking
}

export interface Application {
  id: string;
  jobId: string;
  studentId: string;
  status: 'pending' | 'interview' | 'accepted' | 'rejected';
  matchScore: number;
  appliedAt: Date;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Job, StudentProfile } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function calculateMatchScore(job: Job, profile: StudentProfile): Promise<number> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `
        Calculate a match percentage (0-100) between this student and this job.

        Job: ${JSON.stringify(job)}
        Student: ${JSON.stringify(profile)}

        Rules:
        - High weight on location (City must match or job is online).
        - High weight on availability (Shift types must overlap).
        - Medium weight on skills/experience tags.
        - Physical jobs require city match.

        Return ONLY a JSON object: {"score": number, "reason": "short swedish text"}
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            score: { type: Type.NUMBER },
            reason: { type: Type.STRING }
          },
          required: ["score", "reason"]
        }
      }
    });

    const result = JSON.parse(response.text || '{"score": 75}');
    return result.score;
  } catch (error) {
    console.error("Match calculation failed", error);
    return 75; // Default fallback
  }
}

